ICON_DATA = {
    "ai": "data:image/png;base64,",
    "daily-summary": "data:image/png;base64,",
    "dashboard": "data:image/png;base64,",
    "defects": "data:image/png;base64,",
    "meeting": "data:image/png;base64,",
    "mobile": "data:image/png;base64,",
    "notification": "data:image/png;base64,",
    "progress": "data:image/png;base64,",
    "reports": "data:image/png;base64,",
    "rfi": "data:image/png;base64,",
    "security": "data:image/png;base64,",
    "welcome": "data:image/png;base64,",
}


def get_icon_img(name, size=36):
    src = ICON_DATA.get(name, "")
    if not src:
        return ""
    return f'<img src="{src}" width="{size}" height="{size}" alt="{name}" style="display:block;border:0;" />'
